const seen = new Set();

return items.filter(item => {
  const title = item.json.title;

  if (seen.has(title)) {
    return false;
  }

  seen.add(title);
  return true;
});

let html = `
<html>
<head>
<style>
body {
    font-family: Arial, sans-serif;
    line-height: 1.6;
    max-width: 800px;
    margin: auto;
    background-color: #f5f7fa;
    padding: 20px;
}

.header {
    background-color: #1f2937;
    color: white;
    padding: 20px;
    border-radius: 10px;
    text-align: center;
}

.article {
    background: white;
    padding: 20px;
    margin-top: 20px;
    border-radius: 10px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.08);
}

.title {
    font-size: 22px;
    font-weight: bold;
    color: #111827;
}

.meta {
    color: #6b7280;
    margin-top: 5px;
}

.summary {
    margin-top: 15px;
}

.impact {
    margin-top: 15px;
    padding-left: 15px;
    border-left: 4px solid #2563eb;
}

.tags {
    margin-top: 15px;
    color: #2563eb;
}

.footer {
    text-align: center;
    color: #6b7280;
    margin-top: 30px;
    font-size: 12px;
}
</style>
</head>
<body>

<div class="header">
    <h1>🤖 Daily AI News Digest</h1>
    <p>${new Date().toDateString()}</p>
</div>
`;

items.forEach((item) => {

    const news = item.json.output;

    html += `
    <div class="article">

        <div class="title">
            ${news.title}
        </div>

        <div class="meta">
            📂 ${news.category}
            &nbsp;&nbsp;|&nbsp;&nbsp;
            ⭐ ${news.importance_score}/10
        </div>

        <div class="summary">
            <h3>📋 Summary</h3>
            <p>${news.summary}</p>
        </div>

        <div class="impact">
            <h3>🚀 Industry Impact</h3>
            <p>${news.industry_impact}</p>
        </div>

        <div class="tags">
            🏷️ ${news.tags.join(", ")}
        </div>

    </div>
    `;
});

html += `
<div class="footer">
Generated automatically using n8n AI News Agent
</div>

</body>
</html>
`;

return [{
    json: {
        html
    }
}];
